 KMOD=	dwc_otg
 SRCS=	bus_if.h device_if.h usb_if.h \
-	opt_bus.h opt_usb.h \
-	dwc_otg.c \
+	opt_bus.h opt_usb.h ofw_bus_if.h \
+	dwc_otg.c dwc_otg_fdt.c \
 	pci_if.h

